const W=Math.min(innerWidth,480),H=innerHeight;class S extends Phaser.Scene{create(){this.add.rectangle(W/2,H/2,W,H,0x09111b);this.ship=this.add.rectangle(W/2,H-40,26,14,0x7dd3fc);this.physics.add.existing(this.ship);this.m=this.physics.add.group();this.score=0;this.ui=this.add.text(10,10,'Ore:0');this.c=this.input.keyboard.createCursorKeys();this.r=this.input.keyboard.addKey('R');this.time.addEvent({delay:500,loop:true,callback:()=>{const o=this.add.circle(Phaser.Math.Between(10,W-10),-10,8,0xf59e0b);this.physics.add.existing(o);o.body.setVelocityY(170);this.m.add(o);}});this.physics.add.overlap(this.ship,this.m,(_,o)=>{o.destroy();this.score++;this.ui.setText('Ore:'+this.score);if(this.score>=30)this.end('CLEAR');});}end(m){if(this.over)return;this.over=true;this.add.text(W/2,H/2,m+'\nR').setOrigin(.5);}update(){if(this.r.isDown)this.scene.restart();if(this.over)return;const b=this.ship.body;b.setVelocityX(0);if(this.c.left.isDown)b.setVelocityX(-220);else if(this.c.right.isDown)b.setVelocityX(220);this.m.getChildren().forEach(o=>{if(o.y>H+20)o.destroy();});}}
new Phaser.Game({type:Phaser.AUTO,parent:'game',width:W,height:H,physics:{default:'arcade'},scene:[S]});
